// LoadPledgeCycleResults allows an eager lookup of values, cached into the
// loaded structs of the objects. This is for a 1-M or N-M relationship.
func (pledgeL) LoadPledgeCycleResults(ctx context.Context, e boil.ContextExecutor, singular bool, maybePledge interface{}, mods queries.Applicator) error {
	var slice []*Pledge
	var object *Pledge

	if singular {
		object = maybePledge.(*Pledge)
	} else {
		slice = *maybePledge.(*[]*Pledge)
	}

	args := make([]interface{}, 0, 1)
	if singular {
		if object.R == nil {
			object.R = &pledgeR{}
		}
		args = append(args, object.ID)
	} else {
	Outer:
		for _, obj := range slice {
			if obj.R == nil {
				obj.R = &pledgeR{}
			}

			for _, a := range args {
				if a == obj.ID {
					continue Outer
				}
			}

			args = append(args, obj.ID)
		}
	}

	if len(args) == 0 {
		return nil
	}

	query := NewQuery(qm.From(`pledge_cycle_results`), qm.WhereIn(`pledge_cycle_results.pledge_id in ?`, args...))
	if mods != nil {
		mods.Apply(query)
	}

	results, err := query.QueryContext(ctx, e)
	if err != nil {
		return errors.Wrap(err, "failed to eager load pledge_cycle_results")
	}

	var resultSlice []*PledgeCycleResult
	if err = queries.Bind(results, &resultSlice); err != nil {
		return errors.Wrap(err, "failed to bind eager loaded slice pledge_cycle_results")
	}

	if err = results.Close(); err != nil {
		return errors.Wrap(err, "failed to close results in eager load on pledge_cycle_results")
	}
	if err = results.Err(); err != nil {
		return errors.Wrap(err, "error occurred during iteration of eager loaded relations for pledge_cycle_results")
	}

	if singular {
		object.R.PledgeCycleResults = resultSlice
		for _, foreign := range resultSlice {
			if foreign.R == nil {
				foreign.R = &pledgeCycleResultR{}
			}
			foreign.R.Pledge = object
		}
		return nil
	}

	for _, foreign := range resultSlice {
		for _, local := range slice {
			if local.ID == foreign.PledgeID {
				local.R.PledgeCycleResults = append(local.R.PledgeCycleResults, foreign)
				if foreign.R == nil {
					foreign.R = &pledgeCycleResultR{}
				}
				foreign.R.Pledge = local
				break
			}
		}
	}

	return nil
}

// AddPledgeCycleResults adds the given related objects to the existing relationships
// of the pledge, optionally inserting them as new records.
// Appends related to o.R.PledgeCycleResults.
// Sets related.R.Pledge appropriately.
func (o *Pledge) AddPledgeCycleResults(ctx context.Context, exec boil.ContextExecutor, insert bool, related ...*PledgeCycleResult) error {
	var err error
	for _, rel := range related {
		if insert {
			rel.PledgeID = o.ID
			if err = rel.Insert(ctx, exec, boil.Infer()); err != nil {
				return errors.Wrap(err, "failed to insert into foreign table")
			}
		} else {
			updateQuery := fmt.Sprintf(
				"UPDATE \"pledge_cycle_results\" SET %s WHERE %s",
				strmangle.SetParamNames("\"", "\"", 1, []string{"pledge_id"}),
				strmangle.WhereClause("\"", "\"", 2, pledgeCycleResultPrimaryKeyColumns),
			)
			values := []interface{}{o.ID, rel.ID}

			if boil.IsDebug(ctx) {
				writer := boil.DebugWriterFrom(ctx)
				fmt.Fprintln(writer, updateQuery)
				fmt.Fprintln(writer, values)
			}
			if _, err = exec.ExecContext(ctx, updateQuery, values...); err != nil {
				return errors.Wrap(err, "failed to update foreign table")
			}

			rel.PledgeID = o.ID
		}
	}

	if o.R == nil {
		o.R = &pledgeR{
			PledgeCycleResults: related,
		}
	} else {
		o.R.PledgeCycleResults = append(o.R.PledgeCycleResults, related...)
	}

	for _, rel := range related {
		if rel.R == nil {
			rel.R = &pledgeCycleResultR{
				Pledge: o,
			}
		} else {
			rel.R.Pledge = o
		}
	}
	return nil
}

