// Update does not automatically update the record in case of default values. Use .Reload() to refresh the records.
func (o *Pledge) Update(ctx context.Context, exec boil.ContextExecutor, columns boil.Columns) (int64, error) {
	if !boil.TimestampsAreSkipped(ctx) {
		currTime := time.Now().In(boil.GetLocation())

		o.UpdatedAt = currTime
	}

	var err error
	key := makeCacheKey(columns, nil)
	pledgeUpdateCacheMut.RLock()
	cache, cached := pledgeUpdateCache[key]
	pledgeUpdateCacheMut.RUnlock()

	if !cached {
		wl := columns.UpdateColumnSet(
			pledgeAllColumns,
			pledgePrimaryKeyColumns,
		)

		if !columns.IsWhitelist() {
			wl = strmangle.SetComplement(wl, []string{"created_at"})
		}
		if len(wl) == 0 {
			return 0, errors.New("models: unable to update pledges, could not build whitelist")
		}

		cache.query = fmt.Sprintf("UPDATE \"pledges\" SET %s WHERE %s",
			strmangle.SetParamNames("\"", "\"", 1, wl),
			strmangle.WhereClause("\"", "\"", len(wl)+1, pledgePrimaryKeyColumns),
		)
		cache.valueMapping, err = queries.BindMapping(pledgeType, pledgeMapping, append(wl, pledgePrimaryKeyColumns...))
		if err != nil {
			return 0, err
		}
	}

	values := queries.ValuesFromMapping(reflect.Indirect(reflect.ValueOf(o)), cache.valueMapping)

	if boil.IsDebug(ctx) {
		writer := boil.DebugWriterFrom(ctx)
		fmt.Fprintln(writer, cache.query)
		fmt.Fprintln(writer, values)
	}
	var result sql.Result
	result, err = exec.ExecContext(ctx, cache.query, values...)
	if err != nil {
		return 0, errors.Wrap(err, "models: unable to update pledges row")
	}

	rowsAff, err := result.RowsAffected()
	if err != nil {
		return 0, errors.Wrap(err, "models: failed to get rows affected by update for pledges")
	}

	if !cached {
		pledgeUpdateCacheMut.Lock()
		pledgeUpdateCache[key] = cache
		pledgeUpdateCacheMut.Unlock()
	}

	return rowsAff, nil
}

