		defer ddtracer.Stop()
	}

	// Start server
	s := server.New(fmt.Sprintf(":%s", appenv.GetWithDefault("PORT", "3000")), router.Handler())
	s.Start()
}

func initKafkaProducer(ctx context.Context, topic, purpose string) {
	log.Printf("Initialise kafka publisher with topic %s for %s\n", topic, purpose)
	if err := kafka.InitWriters(ctx, topic); err != nil {
		log.Fatalf("%s", errors.Wrap(err, "unable to instatiate publisher for "+purpose+" with topic "+topic))
	}
	log.Printf("%s kafka publisher with topic %s initialised successfully !!\n", purpose, topic)
}

func initKafkaConsumer(ctx context.Context, groupId, topic, purpose string, consumerHandler kafka.ConsumeHandler) {
	log.Printf("Initialise Kafka consumer with topic %s for %s\n", topic, purpose)
	if err := kafka.InitConsumer(ctx, groupId, topic, consumerHandler); err != nil {
		log.Fatalf("%s", errors.Wrap(err, "unable to instatiate consumer for "+purpose+" with topic "+topic))
	}
	log.Printf("%s kafka consumer with topic %s initialised successfully !!\n", purpose, topic)
}

func initProducerAndConsumerforKafka(ctx context.Context) {
	// initalise kafka for push notification
	initKafkaProducer(ctx, kafka.TopicJarvisPushNotification, "push notification")
	initKafkaConsumer(ctx, kafka.JarvisPushNotificationGroupID, kafka.TopicJarvisPushNotification, "push notification", pushnotification.SendPushNotificationHandler)
	// initalise kafka for bill notification
	initKafkaProducer(ctx, kafka.TopicJarvisBillNotification, "bill notification")
	initKafkaConsumer(ctx, kafka.JarvisBillNotificationGroupID, kafka.TopicJarvisBillNotification, "bill notification", billnotification.SendBillNotificationHandler)
	// initalise kafka for payment notification
	initKafkaProducer(ctx, kafka.TopicJarvisPaymentNotification, "payment notification")
	initKafkaConsumer(ctx, kafka.JarvisPaymentNotificationGroupID, kafka.TopicJarvisPaymentNotification, "payment notification", paymentnotification.SendPaymentNotificationHandler)
	// initalise kafka for smrd notification
	initKafkaProducer(ctx, kafka.TopicJarvisSMRDNotification, "smrd notification")
	initKafkaConsumer(ctx, kafka.JarvisSMRDNotificationGroupID, kafka.TopicJarvisSMRDNotification, "smrd notification", smrdnotification.SendSMRDNotificationHandler)
}

