		pkeyArgs := queries.ValuesFromMapping(reflect.Indirect(reflect.ValueOf(obj)), amiIntervalElecPrimaryKeyMapping)
		args = append(args, pkeyArgs...)
	}

	sql := "SELECT \"ami_interval_elec\".* FROM \"ami_interval_elec\" WHERE " +
		strmangle.WhereClauseRepeated(string(dialect.LQ), string(dialect.RQ), 1, amiIntervalElecPrimaryKeyColumns, len(*o))

	q := queries.Raw(sql, args...)

	err := q.Bind(ctx, exec, &slice)
	if err != nil {
		return errors.Wrap(err, "models: unable to reload all in AmiIntervalElecSlice")
	}

	*o = slice

	return nil
}

// AmiIntervalElecExists checks if the AmiIntervalElec row exists.
func AmiIntervalElecExists(ctx context.Context, exec boil.ContextExecutor, meterID string, date time.Time) (bool, error) {
	var exists bool
	sql := "select exists(select 1 from \"ami_interval_elec\" where \"meter_id\"=$1 AND \"date\"=$2 limit 1)"

	if boil.IsDebug(ctx) {
		writer := boil.DebugWriterFrom(ctx)
		fmt.Fprintln(writer, sql)
		fmt.Fprintln(writer, meterID, date)
	}
	row := exec.QueryRowContext(ctx, sql, meterID, date)

	err := row.Scan(&exists)
	if err != nil {
		return false, errors.Wrap(err, "models: unable to check if ami_interval_elec exists")
	}

	return exists, nil
}

