)

const (
	defaultFilePath = "sampleaccountnumbers.csv"
)

/**
This package is a command line util to be run locally ONLY to handle SAP `active` utility account numbers csv file.

The main intent is to read an csv file, parse it and copy all the account numbers to a local database. Then we can
dump the contents of that particular table and restore them on to QA or Prod DB.

This command can also generate a sample file of random 1.7 million records to be used for testing.

For the input params, please check the flag section. For running the commands, please refer to the Makefile.
*/

func main() {
	ctx := context.Background()

	banner.Print() // Print banner

	if os.Getenv("APPENV") != "test" {
		log.Fatal("This command can only be run on local env")
	}

	var filePath string
	var sheetName string
	var generateSample bool

	flag.StringVar(&filePath, "filepath", defaultFilePath, "File path")
	flag.BoolVar(&generateSample, "generatesample", false, "Generate sample file")
	flag.Parse()

	if generateSample {
		log.Println("Generating sample file")
		generateSampleFile()
		return
	}

	log.Println("Processing input file")
	processFile(ctx, filePath, sheetName)
}

func processFile(ctx context.Context, filePath, sheetName string) {
	start := time.Now()

	log.Println("DB init started")
	// Initialize DB connection
	if _, err := db.Conn(ctx); err != nil {
		log.Fatalf("%s", errors.Wrap(err, "db"))
	}
	log.Println("DB init completed")

	log.Println("DB sanity check started")
	// Sanity check on sqlx.Tx
	// Backward compatibility support to sp-digital/golang v0.4.0
	if err := db.Tx(ctx, nil, func(tx db.Transactor) error {
		txx, err := dbsqlx.Tx(tx)
		if txx == nil {
			return errors.New("tx is nil")
		}
		return err
	}, 3); err != nil {
		log.Fatalf("%s", errors.Wrap(err, "sqlx.Tx"))
	}
	log.Println("DB sanity check completed")

	log.Println("Opening file...")
	f, err := os.Open(filePath)
	if err != nil {
		log.Fatal(err)
	}
	defer f.Close() // this needs to be after the err check

	log.Println("Validating file...")
	rows, err := csv.NewReader(f).ReadAll()
	if err != nil {
		log.Fatal(err)
	}

	rowLength := len(rows)
	// Assuming first row is header and first column contains all the numbers
	if rowLength < 2 {
		log.Fatal("Invalid file")
	}

	log.Printf("File is valid and contains %d account numbers. Starting parsing & insert...\n", rowLength-1)

	if err = db.Tx(ctx, nil, func(tx db.Transactor) error {
		for i := 1; i < rowLength; i++ {
			m := models.SapAccountInfo{
				AccountNumber: sap.PadAccountNo(rows[i][0]),
				Active:        true,
			}
			fmt.Printf("Row: %07d. Value: %s\n", i, m.AccountNumber)
			if err = m.Insert(ctx, tx, boil.Infer()); err != nil {
				log.Fatal(err)
			}
		}
		return nil
	}, 0); err != nil {
		log.Fatal(err)
	}

	log.Printf("Completed inserting %d account numbers in %f minutes", rowLength-1, time.Since(start).Minutes())
}

func generateSampleFile() {
	start := time.Now()

	file, err := os.Create(defaultFilePath)
	if err != nil {
		log.Fatal(err)
	}
	defer file.Close()

	writer := csv.NewWriter(file)
	defer writer.Flush()

	if err = writer.Write([]string{"Account Numbers"}); err != nil {
		log.Fatal(err)
	}

	maxAccNums := 1700000

	for i := 1; i < maxAccNums; i++ {
		accnum := fmt.Sprintf("%07d", i)
		fmt.Println(accnum)
		if err = writer.Write([]string{accnum}); err != nil {
			log.Fatal(err)
		}
	}

	log.Printf("Generated file with %d rows in %f seconds", maxAccNums, time.Since(start).Seconds())
}

