func main() {
	ctx := context.Background()

	// Print banner
	banner.Print()

	// Validate environment variables
	envvar.Validate()

	// Initiate app config
	appCfg := appconfig.DefaultAppConfig()

	// Initiate monitorning
	monitor, err := monitoring.New(
		appCfg,
		monitoring.WithSentry(os.Getenv("SENTRY_DSN")),
		monitoring.WithDatadog(
			os.Getenv("DD_AGENT_HOST"),
			os.Getenv("DD_APM_RECEIVER_PORT"),
			os.Getenv("DD_DOGSTATSD_PORT"),
			false),
	)
	if err != nil {
		log.Fatalf("Error in Monitor setup: %s", err)
	}

	defer monitor.Flush(monitoring.DefaultFlushWait)
	ctx = monitoring.SetInContext(ctx, monitor)

	log.Println("DB init started")
	// Initialize DB connection
	if _, err := db.Conn(ctx); err != nil {
		log.Fatalf("%s", errors.Wrap(err, "db"))
	}
	log.Println("DB init completed")

	log.Println("DB sanity check started")
	// Sanity check on sqlx.Tx
	// Backward compatibility support to sp-digital/golang v0.4.0
	if err := db.Tx(ctx, nil, func(tx db.Transactor) error {
		txx, err := dbsqlx.Tx(tx)
		if txx == nil {
			return errors.New("tx is nil")
		}
		return err
	}, 3); err != nil {
		log.Fatalf("%s", errors.Wrap(err, "sqlx.Tx"))
	}
	log.Println("DB sanity check completed")

	// Start all kafka
	initProducerAndConsumerforKafka(ctx)

	// Start all datastreams
	log.Println("CO2E data stream init started")
	co2e.InitDataStream()
	log.Println("CO2E data stream init completed")
	log.Println("PostalCode data stream init started")
	datastream.InitPostalCode()
	log.Println("PostalCode data stream init completed")

	// Auth0 JWKS
	log.Println("AUTH0 Jwks init started")
	auth0.InitJwks()
	log.Println("AUTH0 Jwks init completed")

	// Downtime mechanism
	log.Println("Downtime poller init started")
	stopPollingDowntime := downtime.Poll(ctx, downtime.Interval)
	defer stopPollingDowntime()
	log.Println("Downtime poller init completed")

	// OpenTracing
	log.Println("Zipkin init started")
	if err := zipkin.InitNoRecorder(); err != nil {
		log.Fatalf("%s", errors.Wrap(err, "opentracing"))
	}
	log.Println("Zipkin init completed")
	// Logger
	if os.Getenv("LOG_COLOR") == "true" {
		loglib.SetFormatter(loglib.FormatterTextColor)
	}

	// Initialize Datadog tracer
	// Note: Dev env is not supported
	if os.Getenv("APPENV") != "dev" {
		ddAppCfg := router.PrepareDataDogConfig()
		ddtracer.Start(
			ddtracer.WithGlobalTag("team", ddAppCfg.ProjectTeam),
			ddtracer.WithGlobalTag("project", ddAppCfg.ProjectName),
			ddtracer.WithGlobalTag("subcomponent", ddAppCfg.SubComponentName),
			ddtracer.WithEnv(os.Getenv("APPENV")),
			ddtracer.WithAnalytics(true),
			ddtracer.WithDebugStack(true),
			ddtracer.WithRuntimeMetrics(),
		)
		log.Println("Initializing Datadog tracer")
		defer ddtracer.Stop()
	}

	// Start server
	s := server.New(fmt.Sprintf(":%s", appenv.GetWithDefault("PORT", "3000")), router.Handler())
	s.Start()
}

func initKafkaProducer(ctx context.Context, topic, purpose string) {
	log.Printf("Initialise kafka publisher with topic %s for %s\n", topic, purpose)
	if err := kafka.InitWriters(ctx, topic); err != nil {
		log.Fatalf("%s", errors.Wrap(err, "unable to instatiate publisher for "+purpose+" with topic "+topic))
	}
	log.Printf("%s kafka publisher with topic %s initialised successfully !!\n", purpose, topic)
}

func initKafkaConsumer(ctx context.Context, groupId, topic, purpose string, consumerHandler kafka.ConsumeHandler) {
	log.Printf("Initialise Kafka consumer with topic %s for %s\n", topic, purpose)
	if err := kafka.InitConsumer(ctx, groupId, topic, consumerHandler); err != nil {
		log.Fatalf("%s", errors.Wrap(err, "unable to instatiate consumer for "+purpose+" with topic "+topic))
	}
	log.Printf("%s kafka consumer with topic %s initialised successfully !!\n", purpose, topic)
}

func initProducerAndConsumerforKafka(ctx context.Context) {
	// initalise kafka for push notification
	initKafkaProducer(ctx, kafka.TopicJarvisPushNotification, "push notification")
	initKafkaConsumer(ctx, kafka.JarvisPushNotificationGroupID, kafka.TopicJarvisPushNotification, "push notification", pushnotification.SendPushNotificationHandler)
	// initalise kafka for bill notification
	initKafkaProducer(ctx, kafka.TopicJarvisBillNotification, "bill notification")
	initKafkaConsumer(ctx, kafka.JarvisBillNotificationGroupID, kafka.TopicJarvisBillNotification, "bill notification", billnotification.SendBillNotificationHandler)
	// initalise kafka for payment notification
	initKafkaProducer(ctx, kafka.TopicJarvisPaymentNotification, "payment notification")
	initKafkaConsumer(ctx, kafka.JarvisPaymentNotificationGroupID, kafka.TopicJarvisPaymentNotification, "payment notification", paymentnotification.SendPaymentNotificationHandler)
	// initalise kafka for smrd notification
	initKafkaProducer(ctx, kafka.TopicJarvisSMRDNotification, "smrd notification")
	initKafkaConsumer(ctx, kafka.JarvisSMRDNotificationGroupID, kafka.TopicJarvisSMRDNotification, "smrd notification", smrdnotification.SendSMRDNotificationHandler)
}

