    created_at timestamp with time zone DEFAULT current_timestamp NOT NULL,
    updated_by text CHECK (updated_by::text <> ''::text) NOT NULL,
    updated_at timestamp with time zone DEFAULT current_timestamp NOT NULL
);
COMMENT ON COLUMN orders.iam_id IS 'IAM ID of the user who place the order';
COMMENT ON COLUMN orders.status IS 'Status of the order';
COMMENT ON COLUMN orders.total_price IS 'Total price of the order in cents';
COMMENT ON COLUMN orders.payment_status IS 'Payment status of the order';
COMMENT ON COLUMN orders.customer_details IS 'Snapshot of customers shipping details e.g. shipping address, customer name, customer phone numer (will be encrypted)';


CREATE TABLE IF NOT EXISTS order_items (
    id BIGSERIAL PRIMARY KEY,
    order_id text CHECK (order_id::text <> ''::text) references orders(id) NOT NULL,
    product_id text CHECK (product_id::text <> ''::text) references products(id) NOT NULL,
    product_details json NOT NULL,
    price int NOT NULL,
    total_price int NOT NULL,
    quantity INTEGER NOT NULL,
    created_by text CHECK (created_by::text <> ''::text) NOT NULL,
    created_at timestamp with time zone DEFAULT current_timestamp NOT NULL,
    updated_by text CHECK (updated_by::text <> ''::text) NOT NULL,
    updated_at timestamp with time zone DEFAULT current_timestamp NOT NULL
);
COMMENT ON COLUMN order_items.order_id IS 'Order ID of the order the order item is part of';
COMMENT ON COLUMN order_items.product_id IS 'Product ID of the product the order item references';
COMMENT ON COLUMN order_items.product_details IS 'Snapshot of the product at the time of order creation';
COMMENT ON COLUMN order_items.price IS 'Unit price of the order item in cents';
COMMENT ON COLUMN order_items.total_price IS 'Total price (unit price * quantity) of the order item in cents';
COMMENT ON COLUMN order_items.quantity IS 'Quantity of the order item';

