var (
	kafkaTimeOut     = time.Minute
	defaultBrokerURL = os.Getenv("KAFKA_BROKER_URL")
	certFile         = "/kafka-certs/cert.pem"
	certKey          = "/kafka-certs/key.pem"
	caFile           = "/kafka-certs/ca.pem"
)

// tlsConfig returns the TLS config for Kafka
func tlsConfig() *tls.Config {
	// Load client cert
	cert, err := tls.LoadX509KeyPair(certFile, certKey)
	if err != nil {
		log.Fatal(err)
	}

	// Load CA cert
	caCert, err := ioutil.ReadFile(caFile)
	if err != nil {
		log.Fatal(err)
	}
	caCertPool := x509.NewCertPool()
	caCertPool.AppendCertsFromPEM(caCert)

	cfg := &tls.Config{
		Certificates: []tls.Certificate{cert},
		RootCAs:      caCertPool,
	}
	cfg.BuildNameToCertificate()
	return cfg
}

